const $ = (s, root=document) => root.querySelector(s);
const $$ = (s, root=document) => [...root.querySelectorAll(s)];
const esc = (v='') => String(v ?? '').replace(/[&<>'"]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
const fmtMoney = v => Number(v||0).toLocaleString('pt-BR',{style:'currency',currency:'BRL'});
const fmtDate = v => v ? new Date(v).toLocaleString('pt-BR') : '—';
const statusLabel = v => String(v||'').replaceAll('_',' ');
const state = { page:'dashboard', setup:null, settings:null, products:[], categories:[], integrations:null, funnel:null };

function toast(message,type='success'){ const el=document.createElement('div'); el.className=`toast ${type}`; el.textContent=message; $('#toast').appendChild(el); setTimeout(()=>el.remove(),3500); }
async function api(url,{method='GET',body,headers={}}={}){
  const res=await fetch(url,{method,headers:{...(body!==undefined?{'content-type':'application/json'}:{}),...(method!=='GET'?{'x-requested-with':'jetbot-panel'}:{}),...headers},body:body!==undefined?JSON.stringify(body):undefined});
  const text=await res.text(); let data={}; try{data=text?JSON.parse(text):{}}catch{data={error:text||'Resposta inválida.'}}
  if(!res.ok) throw new Error(data.error||`Erro ${res.status}`); return data;
}
function openModal(html,wide=false){ $('#modalContent').innerHTML=html; $('.modal-card').style.width=wide?'min(1100px,100%)':''; $('#modal').classList.remove('hidden'); }
function closeModal(){ $('#modal').classList.add('hidden'); $('#modalContent').innerHTML=''; $('.modal-card').style.width=''; }
function copyText(text){ navigator.clipboard.writeText(text).then(()=>toast('Copiado!')); }
function status(v){ return `<span class="status ${esc(v)}">${esc(statusLabel(v)||'—')}</span>`; }
function empty(text){ return `<div class="empty">${esc(text)}</div>`; }
function lines(v){ return Array.isArray(v)?v.join('\n'):String(v||''); }
function parseLines(v){ return String(v||'').split(/\r?\n/).map(x=>x.trim()).filter(Boolean); }
function parseFaq(v){ return String(v||'').split(/\r?\n/).map(line=>{const i=line.indexOf('|');return i>0?{question:line.slice(0,i).trim(),answer:line.slice(i+1).trim()}:null}).filter(Boolean); }
function faqLines(v){ return (Array.isArray(v)?v:[]).map(x=>`${x.question}|${x.answer}`).join('\n'); }
function funnelSequenceLines(v){ return (Array.isArray(v)?v:[]).map(x=>`${Number(x.delayMinutes||1)}|${x.kind||'marketing'}|${String(x.text||'').replace(/\n/g,'\\n')}`).join('\n'); }
function parseFunnelSequence(v){ return String(v||'').split(/\r?\n/).map((line,index)=>{const p=line.split('|');if(p.length<3)return null;return{id:`gift-${index+1}`,delayMinutes:Number(p.shift()||1),kind:(p.shift()==='transactional'?'transactional':'marketing'),text:p.join('|').replace(/\\n/g,'\n').trim()}}).filter(x=>x&&x.text); }
function groupsLines(v){ return (Array.isArray(v)?v:[]).map(x=>`${x.nome||'Grupo'}|${x.groupId||''}|${x.ativo!==false?'true':'false'}`).join('\n'); }
function parseGroups(v){ return String(v||'').split(/\r?\n/).map(line=>{const [nome,groupId,ativo='true']=line.split('|').map(x=>x.trim());return groupId?{nome:nome||'Grupo',groupId,ativo:ativo!=='false'}:null}).filter(Boolean); }
function formDataObject(form){ const fd=new FormData(form); return Object.fromEntries(fd.entries()); }
function showLogin(){ $('#login').classList.remove('hidden'); $('#app').classList.add('hidden'); }
function showApp(){ $('#login').classList.add('hidden'); $('#app').classList.remove('hidden'); }

const pages={
 dashboard:['Painel','Visão geral da operação'], setup:['Setup inicial','Configure o robô sem editar arquivos'], products:['Produtos','Apresentação, oferta, estoque e entrega'], orders:['Pedidos','Pagamentos e entregas'], crm:['CRM / Leads','Contatos, funil e consentimento'], tickets:['Suporte','Atendimento humano'], automation:['Automação','Carrinho, pós-venda e renovação'], funnel:['Funil Presentes','Ads → WhatsApp → grupo/página → aquecimento → oferta'], campaigns:['Campanhas','Disparos, remarketing, grupos e agenda'], integrations:['Integrações','WhatsApp, Evolution API, leads e webhooks'], settings:['Configurações','Marca, vendas, pagamentos e IA'], security:['Logs e backups','Segurança e histórico']
};
async function navigate(page){
  state.page=page; $$('#nav button').forEach(b=>b.classList.toggle('active',b.dataset.page===page));
  $('#pageTitle').textContent=pages[page]?.[0]||'Painel'; $('#pageSubtitle').textContent=pages[page]?.[1]||''; $('#content').innerHTML='<div class="empty">Carregando...</div>';
  try{ await ({dashboard:renderDashboard,setup:renderSetup,products:renderProducts,orders:renderOrders,crm:renderCrm,tickets:renderTickets,automation:renderAutomation,funnel:renderFunnel,campaigns:renderCampaigns,integrations:renderIntegrations,settings:renderSettings,security:renderSecurity}[page]||renderDashboard)(); }
  catch(err){ $('#content').innerHTML=`<div class="alert danger"><b>Não foi possível carregar.</b><br>${esc(err.message)}</div>`; }
  $('#sidebar').classList.remove('open');
}
async function refreshStatus(){ try{ const s=await api('/api/status'); const w=s.whatsapp||{}; const badge=$('#waBadge'); badge.textContent=w.connected?`WhatsApp conectado · ${w.provider||'local'}`:w.status==='qr'?'Aguardando QR Code':`WhatsApp ${w.status||'offline'}`; badge.className=`badge ${w.connected?'ok':w.status==='qr'?'warn':'error'}`; }catch{} }

async function renderDashboard(){
  const d=await api('/api/dashboard'); state.setup=d.setup;
  const setupPct=Math.round(Object.values(d.setup.checklist||{}).filter(Boolean).length/Math.max(1,Object.keys(d.setup.checklist||{}).length)*100);
  $('#content').innerHTML=`
  ${!d.setup.ready?`<div class="setup-hero"><span class="eyebrow">CONFIGURAÇÃO PENDENTE</span><h2>Termine o setup para começar a vender</h2><p>O assistente orienta marca, administrador, WhatsApp, produto e pagamento.</p><div class="progress"><span style="width:${setupPct}%"></span></div><div class="toolbar" style="margin-top:14px"><button data-go="setup">Continuar setup</button></div></div>`:''}
  <div class="hero-banner"><div><span class="eyebrow">CENTRAL DE OPERAÇÃO</span><h2>${esc((await api('/api/settings')).bot.nome)}</h2><p>Acompanhe vendas, clientes, suporte e automações em tempo real.</p></div><div class="toolbar"><a class="button-link" href="/catalogo" target="_blank"><button type="button" class="secondary">Abrir loja pública</button></a><button class="secondary" data-action="diagnostics">Executar diagnóstico</button>${!d.runtime.whatsapp.connected&&d.runtime.whatsapp.qrDataUrl?'<button data-action="show-qr">Ver QR Code</button>':''}</div></div>
  <div class="grid cards section">
    <div class="card metric"><small>Faturamento</small><strong>${fmtMoney(d.orders.revenue||0)}</strong><span class="muted">Pedidos entregues</span></div>
    <div class="card metric"><small>Pedidos</small><strong>${d.orders.total||0}</strong><span class="muted">${d.orders.pending||0} pendente(s)</span></div>
    <div class="card metric"><small>Leads</small><strong>${d.leads.total||0}</strong><span class="muted">${d.leads.customer||0} cliente(s)</span></div>
    <div class="card metric"><small>Suporte</small><strong>${d.tickets.open||0}</strong><span class="muted">chamado(s) aberto(s)</span></div>
  </div>
  <div class="grid two section">
    <div class="card"><div class="section-head"><div><h3>Operação</h3><p>Status essencial</p></div></div><div class="setup-list">
      ${setupRow('WhatsApp conectado',d.runtime.whatsapp.connected)}${setupRow('Produtos ativos',d.products.active>0)}${setupRow('Estoque disponível',d.products.outOfStock===0&&d.products.active>0)}${setupRow('Automação saudável',d.health?.status!=='error')}
    </div></div>
    <div class="card"><div class="section-head"><div><h3>Alertas</h3><p>Itens que precisam de atenção</p></div><button class="secondary small-btn" data-go="automation">Ver tudo</button></div>${d.alerts?.length?d.alerts.slice(0,5).map(a=>`<div class="diagnostic"><span>${esc(a.message)}</span>${status(a.severity)}</div>`).join(''):empty('Nenhum alerta aberto.')}</div>
  </div>`;
}
function setupRow(label,ok){ return `<div class="setup-item"><span>${esc(label)}</span><b class="${ok?'ok':'no'}">${ok?'✓ Pronto':'✕ Pendente'}</b></div>`; }

async function renderSetup(){
  const s=await api('/api/setup'); state.setup=s; state.settings=s.config; state.integrations=s.integrations;
  const c=s.config; const integ=s.integrations;
  const checks=s.checklist||{};
  $('#content').innerHTML=`<div class="setup-hero"><span class="eyebrow">ASSISTENTE DE CONFIGURAÇÃO</span><h2>Deixe o robô pronto em poucos passos</h2><p>Você pode voltar e editar tudo depois. Nenhuma configuração importante precisa ser alterada em arquivos.</p><div class="steps">${[['Negócio','business'],['Admin','admin'],['Provedor','whatsappProvider'],['Conexão','whatsappConnected'],['Produto','product'],['Explicação','productExplanation'],['Pagamento','payment'],['Automação','automation'],['Funil','funnel']].map(([x,k],i)=>`<div class="step-chip ${checks[k]?'done':''}">${i+1}. ${x}</div>`).join('')}</div></div>
  <div class="grid two">
    <div class="card"><h3>1. Seu negócio</h3><form id="setupBusiness" class="form-grid"><label>Tipo de negócio<select name="tipoNegocio">${businessOptions(c.bot.tipoNegocio)}</select></label><label>Nome da marca<input name="nome" value="${esc(c.bot.nome)}" required></label><label>Nome do assistente<input name="nomeAssistente" value="${esc(c.bot.nomeAssistente)}"></label><label>Link principal<input name="linkPrincipal" value="${esc(c.bot.linkPrincipal)}" placeholder="https://..."></label><label>Número público do WhatsApp<input name="whatsappPublicNumber" value="${esc(c.bot.whatsappPublicNumber||'')}" placeholder="5551999999999"></label><label>Logo da marca (URL)<input name="logoUrl" value="${esc(c.bot.logoUrl||'')}" placeholder="https://..."></label><label>Cor principal<input name="primaryColor" type="color" value="${esc(c.bot.primaryColor||'#00e676')}"></label><label class="full">Título da loja pública<input name="catalogTitle" value="${esc(c.bot.catalogTitle||'Conheça nossas soluções')}"></label><label class="full">Subtítulo da loja pública<textarea name="catalogSubtitle">${esc(c.bot.catalogSubtitle||'')}</textarea></label><label class="full">Descrição do negócio<textarea name="descricaoNegocio" placeholder="Explique o que sua empresa vende e para quem.">${esc(c.bot.descricaoNegocio)}</textarea></label><div class="full toolbar"><button>Salvar negócio</button><button type="button" class="secondary" data-action="apply-template">Aplicar modelo de textos</button></div></form></div>
    <div class="card"><h3>2. Administradores</h3><p class="muted">Um número por linha, com 55 + DDD + número.</p><form id="setupAdmins"><label>Números administrativos<textarea name="adminNumbers" placeholder="5551999999999">${esc(lines(c.bot.adminNumbers))}</textarea></label><button>Salvar administradores</button></form></div>
    <div class="card"><h3>3. WhatsApp</h3><p>Modo atual: <b>${integ.whatsapp.provider==='evolution'?'Evolution API':'QR Code direto'}</b></p><p class="muted">A conexão e as credenciais são configuradas na página de Integrações.</p><button data-go="integrations">Configurar WhatsApp</button></div>
    <div class="card"><h3>4. Primeiro produto</h3><p>Produtos ativos: <b>${(await api('/api/products')).filter(p=>p.ativo!==false).length}</b></p><p class="muted">Cadastre uma oferta completa. O bot explica antes de gerar o PIX.</p><div class="toolbar"><button data-action="setup-product-template">Criar modelo do segmento</button><button class="secondary" data-action="new-product">Cadastrar manualmente</button></div></div>
    <div class="card"><h3>5. Pagamento</h3><p>Mercado Pago: ${c.pagamentos.mercadoPago.ativo?'ativo':'inativo'} · PushinPay: ${c.pagamentos.pushinpay.ativo?'ativo':'inativo'} · PIX manual: ${c.pagamentos.pixManual.ativo?'ativo':'inativo'}</p><button data-go="settings">Configurar pagamentos</button></div>
    <div class="card"><h3>6. IA, automação e funil</h3><p class="muted">A IA usa o catálogo real. Automações cuidam de recuperação, pós-venda, renovação e presentes.</p><div class="toolbar"><button data-go="settings">Configurar IA</button><button class="secondary" data-go="automation">Automações</button><button class="secondary" data-go="funnel">Funil presentes</button></div></div>
  </div>
  <div class="card section"><div class="section-head"><div><h3>7. Validação final</h3><p>Itens obrigatórios para operar.</p></div><button data-action="complete-setup">Concluir setup</button></div><div class="check-grid">${Object.entries(checks).map(([k,v])=>`<div class="diagnostic"><span>${setupNames[k]||k}</span><b class="${v?'ok':'no'}">${v?'✓':'✕'}</b></div>`).join('')}</div></div>`;
}
const setupNames={business:'Marca configurada',admin:'Administrador cadastrado',whatsappProvider:'Provedor do WhatsApp definido',whatsappConnected:'WhatsApp realmente conectado',product:'Produto ativo',productExplanation:'Produto com explicação completa',payment:'Pagamento configurado',automation:'Automação disponível',ai:'IA configurada (opcional)',funnel:'Funil de presentes configurado (opcional)'};
function businessOptions(selected){ const opts={digital_products:'Produtos digitais',ecommerce:'Loja / E-commerce',services:'Prestação de serviços',local_business:'Negócio local',education:'Cursos e educação',agency:'Agência / consultoria',subscription:'Assinaturas e planos',restaurant:'Restaurante / Delivery',beauty:'Beleza / Estética',health:'Saúde e bem-estar',real_estate:'Imóveis',automotive:'Automotivo',events:'Eventos',custom:'Outro negócio'}; return Object.entries(opts).map(([v,l])=>`<option value="${v}" ${v===selected?'selected':''}>${l}</option>`).join(''); }

async function loadProducts(){ [state.products,state.categories]=await Promise.all([api('/api/products'),api('/api/categories')]); }
async function renderProducts(){
  await loadProducts();
  $('#content').innerHTML=`<div class="hero-banner"><div><h2>Produtos que vendem explicando</h2><p>Cadastre benefícios, conteúdo, público, garantia, FAQ, imagem, entrega e upsell. O pagamento só aparece depois da apresentação.</p></div><div class="toolbar"><button class="secondary" data-action="new-category">+ Categoria</button><button data-action="new-product">+ Novo produto</button></div></div>
  <div class="section"><div class="section-head"><div><h3>${state.products.length} produto(s)</h3><p>${state.categories.length} categoria(s)</p></div></div><div class="grid">${state.products.length?state.products.map(productCard).join(''):empty('Nenhum produto cadastrado. Clique em “Novo produto”.')}</div></div>`;
}
function productCard(p){ const cat=state.categories.find(c=>c.id===p.categoriaId)?.nome||'Sem categoria'; return `<div class="card product-card"><img class="product-thumb" src="${esc(p.imagemUrl||'data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%22120%22 height=%2295%22%3E%3Crect width=%22100%25%22 height=%22100%25%22 fill=%22%231b2742%22/%3E%3Ctext x=%2250%25%22 y=%2255%25%22 text-anchor=%22middle%22 fill=%22%23a9b4cf%22 font-size=%2230%22%3E%F0%9F%93%A6%3C/text%3E%3C/svg%3E')}" onerror="this.style.display='none'"><div><h3>${esc(p.nome)}</h3><p>${esc(p.descricaoCurta||p.descricao||'Sem descrição.')}</p><div class="product-meta"><b>${fmtMoney(p.preco)}</b><span class="status ${p.ativo?'active':'cancelled'}">${p.ativo?'ativo':'inativo'}</span><span class="status">${esc(cat)}</span><span class="status">${esc(p.deliveryType||'stock')}</span><span class="status ${p.estoque>0?'active':'warning'}">estoque ${p.estoque}</span></div></div><div class="product-actions"><button class="small-btn" data-action="edit-product" data-id="${p.id}">Editar</button><button class="secondary small-btn" data-action="stock" data-id="${p.id}">Estoque</button><button class="danger small-btn" data-action="delete-product" data-id="${p.id}">Excluir</button></div></div>`; }
function productForm(p={}){
  return `<h2>${p.id?'Editar':'Novo'} produto</h2><p class="muted">Preencha como se estivesse explicando pessoalmente ao cliente.</p><form id="productForm" class="form-grid"><input type="hidden" name="id" value="${esc(p.id)}">
  <label>Nome do produto<input name="nome" value="${esc(p.nome)}" required></label><label>Categoria<select name="categoriaId"><option value="">Selecione</option>${state.categories.map(c=>`<option value="${c.id}" ${c.id===p.categoriaId?'selected':''}>${esc(c.nome)}</option>`).join('')}${!state.categories.length?'<option value="__new__">Criar categoria padrão</option>':''}</select></label>
  <label>Preço atual<input name="preco" type="number" step="0.01" min="0" value="${p.preco??''}" required></label><label>Preço anterior (opcional)<input name="precoDe" type="number" step="0.01" min="0" value="${p.precoDe??''}"></label>
  <label class="full">Descrição curta<input name="descricaoCurta" maxlength="320" value="${esc(p.descricaoCurta)}" placeholder="Uma frase forte e clara."></label>
  <label class="full">Explicação completa<textarea name="descricao" placeholder="O que é, como funciona, problema que resolve e resultado esperado.">${esc(p.descricao)}</textarea></label>
  <label>Benefícios — um por linha<textarea name="beneficios">${esc(lines(p.beneficios))}</textarea></label><label>O que está incluído — um por linha<textarea name="inclui">${esc(lines(p.inclui))}</textarea></label>
  <label class="full">Para quem é<textarea name="publicoAlvo">${esc(p.publicoAlvo)}</textarea></label><label>Garantia / condições<textarea name="garantia">${esc(p.garantia)}</textarea></label><label>Prova social / credibilidade<textarea name="provaSocial">${esc(p.provaSocial)}</textarea></label>
  <label class="full">FAQ — uma por linha no formato Pergunta|Resposta<textarea name="faq" placeholder="Como recebo?|Após a confirmação...">${esc(faqLines(p.faq))}</textarea></label>
  <label>URL da imagem<input name="imagemUrl" value="${esc(p.imagemUrl)}" placeholder="https://..."></label><label>URL do vídeo<input name="videoUrl" value="${esc(p.videoUrl)}" placeholder="https://..."></label>
  <label>Texto do botão<input name="ctaTexto" value="${esc(p.ctaTexto||'QUERO COMPRAR')}"></label><label>Produto de upsell<select name="upsellProductId"><option value="">Nenhum</option>${state.products.filter(x=>x.id!==p.id).map(x=>`<option value="${x.id}" ${x.id===p.upsellProductId?'selected':''}>${esc(x.nome)}</option>`).join('')}</select></label>
  <label>Validade em dias<input name="validityDays" type="number" min="0" value="${p.validityDays??0}"></label><label>Alerta de estoque<input name="lowStockThreshold" type="number" min="0" value="${p.lowStockThreshold??3}"></label>
  <label>Tipo de entrega<select name="deliveryType"><option value="stock" ${(!p.deliveryType||p.deliveryType==='stock')?'selected':''}>Estoque: uma linha por venda</option><option value="link" ${p.deliveryType==='link'?'selected':''}>Link fixo automático</option><option value="webhook" ${p.deliveryType==='webhook'?'selected':''}>API/Webhook externo</option><option value="manual" ${p.deliveryType==='manual'?'selected':''}>Entrega manual</option></select></label><label>Ordem<input name="ordem" type="number" min="0" value="${p.ordem??0}"></label>
  <label class="full">Link fixo de entrega<input name="deliveryLink" value="${esc(p.deliveryLink)}" placeholder="Usado quando o tipo é Link fixo"></label><label class="full">Webhook de entrega<input name="deliveryWebhookUrl" value="${esc(p.deliveryWebhookUrl)}" placeholder="API que retorna delivery, access ou message"></label>
  <label class="full">Tutorial pós-venda<textarea name="tutorial">${esc(p.tutorial)}</textarea></label><label class="full">Mensagem de entrega<textarea name="deliveryMessage" placeholder="Use {{produto}}, {{entrega}} e {{pagamento}}">${esc(p.deliveryMessage)}</textarea></label>
  <label class="check-line"><input type="checkbox" name="ativo" ${p.id?(p.ativo?'checked':''):'checked'}> Produto ativo</label><label class="check-line"><input type="checkbox" name="destaque" ${p.destaque?'checked':''}> Mostrar em destaque</label><label class="check-line"><input type="checkbox" name="entregaAutomatica" ${p.id?(p.entregaAutomatica?'checked':''):'checked'}> Entrega automática</label>
  ${!p.id?'<label class="full">Estoque inicial — uma entrega por linha<textarea name="stock"></textarea></label>':''}<div class="full toolbar"><button>Salvar produto</button><button type="button" class="secondary" data-close>Cancelar</button></div></form>`;
}

async function renderOrders(){ const orders=await api('/api/orders'); $('#content').innerHTML=`<div class="section-head"><div><h3>Pedidos</h3><p>Acompanhe cobrança, aprovação e entrega.</p></div></div>${orders.length?`<div class="table-wrap"><table><thead><tr><th>Cliente</th><th>Produto</th><th>Valor</th><th>Pagamento</th><th>Entrega</th><th>Data</th><th>Ações</th></tr></thead><tbody>${orders.map(o=>`<tr><td>${esc(o.customerPhone)}</td><td>${esc(o.productName||o.product?.nome)}</td><td>${fmtMoney(o.amount||o.product?.preco)}</td><td>${status(o.status)}</td><td>${status(o.deliveryStatus)}</td><td>${fmtDate(o.createdAt)}</td><td>${['delivered'].includes(o.deliveryStatus)?'—':`<button class="small-btn" data-action="deliver-order" data-id="${o.id}">Entregar / tentar</button>`}</td></tr>`).join('')}</tbody></table></div>`:empty('Nenhum pedido registrado.')}`; }

async function renderCrm(){ const leads=await api('/api/leads'); $('#content').innerHTML=`<div class="hero-banner"><div><h2>CRM e captação de leads</h2><p>Organize o funil e registre consentimento. Leads importados entram sem autorização de marketing por padrão.</p></div><div class="toolbar"><button data-action="import-leads">Importar leads</button><button class="secondary" data-go="integrations">Conectar extrator</button></div></div><div class="section">${leads.length?`<div class="table-wrap"><table><thead><tr><th>Contato</th><th>Nome / empresa</th><th>Origem</th><th>Etapa</th><th>Consentimento</th><th>Atualização</th><th></th></tr></thead><tbody>${leads.map(l=>`<tr><td>${esc(l.telefone||l.chatId)}</td><td><b>${esc(l.nome||'Sem nome')}</b><br><span class="muted">${esc(l.empresa||'')}</span></td><td>${esc(l.source||l.origem||'WhatsApp')}</td><td>${status(l.stage)}</td><td>${l.optIn?'<span class="status active">autorizado</span>':'<span class="status warning">não autorizado</span>'}</td><td>${fmtDate(l.updatedAt||l.ultimaInteracaoEm)}</td><td><button class="small-btn secondary" data-action="edit-lead" data-id="${encodeURIComponent(l.chatId||l.id)}">Editar</button></td></tr>`).join('')}</tbody></table></div>`:empty('Nenhum lead ainda.')}</div>`; }

async function renderTickets(){ const tickets=await api('/api/tickets'); $('#content').innerHTML=tickets.length?tickets.map(t=>`<div class="ticket"><div class="ticket-head"><div><h3>${esc(t.subject)}</h3><span class="muted">${esc(t.customerPhone)} · ${fmtDate(t.createdAt)}</span></div>${status(t.status)}</div><div class="messages">${(t.messages||[]).map(m=>`<div class="message ${esc(m.sender)}">${esc(m.text)}<small>${fmtDate(m.timestamp)}</small></div>`).join('')||'<span class="muted">Sem mensagens.</span>'}</div>${!['resolved','cancelled'].includes(t.status)?`<form class="ticketReply" data-id="${t.id}"><textarea name="text" placeholder="Escreva sua resposta..." required></textarea><div class="toolbar"><button>Responder</button><button name="resolve" value="1" class="success">Responder e resolver</button><button type="button" class="secondary" data-action="resolve-ticket" data-id="${t.id}">Marcar resolvido</button></div></form>`:''}</div>`).join(''):empty('Nenhum chamado registrado.'); }

async function renderAutomation(){ const a=await api('/api/automation'); const c=a.config; $('#content').innerHTML=`<div class="hero-banner"><div><h2>Motor de automação persistente</h2><p>Carrinho abandonado, pós-venda, upsell, renovação, limites e retentativas continuam mesmo após reinício.</p></div><div class="toolbar"><button data-action="run-automation">Executar agora</button><button class="secondary" data-action="run-monitor">Diagnóstico</button></div></div><div class="grid cards section"><div class="card metric"><small>Agendadas</small><strong>${a.stats.scheduled||0}</strong></div><div class="card metric"><small>Falhas</small><strong>${a.stats.failed||0}</strong></div><div class="card metric"><small>Concluídas</small><strong>${a.stats.completed||0}</strong></div><div class="card metric"><small>Alertas</small><strong>${a.alerts.filter(x=>x.status==='open').length}</strong></div></div>
  <div class="card section"><div class="section-head"><div><h3>Configuração completa</h3><p>Modo visual para itens principais e JSON avançado para controle total.</p></div></div><form id="automationForm" class="form-grid"><label class="check-line"><input type="checkbox" name="enabled" ${c.enabled?'checked':''}> Automação ativada</label><label>Intervalo do worker (segundos)<input name="workerIntervalSeconds" type="number" min="5" value="${c.workerIntervalSeconds}"></label><label>Máximo de mensagens/dia<input name="maxMessages" type="number" min="1" value="${c.limits.maxMessagesPerContactPerDay}"></label><label>Máximo de ofertas/dia<input name="maxMarketing" type="number" min="0" value="${c.limits.maxMarketingPerContactPerDay}"></label><label>Início do horário silencioso<input name="quietStart" value="${esc(c.quietHours.start)}"></label><label>Fim do horário silencioso<input name="quietEnd" value="${esc(c.quietHours.end)}"></label><label class="full">Configuração avançada JSON<textarea class="json-editor" name="advanced">${esc(JSON.stringify(c,null,2))}</textarea></label><div class="full toolbar"><button>Salvar automação</button></div></form></div>
  <div class="grid two section"><div class="card"><h3>Fila recente</h3>${a.jobs.slice(0,20).map(j=>`<div class="diagnostic"><div><b>${esc(j.type)}</b><br><span class="muted">${fmtDate(j.runAt)} · tentativa ${j.attempts||0}</span></div><div class="toolbar">${status(j.status)}${j.status==='failed'?`<button class="small-btn" data-action="retry-job" data-id="${j.id}">Tentar</button>`:''}${['scheduled','failed'].includes(j.status)?`<button class="small-btn danger" data-action="cancel-job" data-id="${j.id}">Cancelar</button>`:''}</div></div>`).join('')||empty('Fila vazia.')}</div><div class="card"><h3>Alertas</h3>${a.alerts.filter(x=>x.status==='open').slice(0,20).map(x=>`<div class="diagnostic"><span>${esc(x.message)}</span><button class="small-btn secondary" data-action="resolve-alert" data-id="${x.id}">Resolver</button></div>`).join('')||empty('Sem alertas.')}</div></div>`; }

async function renderFunnel(){
  const [d,business]=await Promise.all([api('/api/funnel'),api('/api/settings')]); state.funnel=d; const f=d.config; const wa=String(business.bot.whatsappPublicNumber||'').replace(/\D/g,''); const adLink=wa?`https://wa.me/${wa}?text=${encodeURIComponent(`${f.adMessage} [${f.campaignCode}]`)}`:'';
  $('#content').innerHTML=`<div class="hero-banner cyber"><div><span class="eyebrow">FUNIL AUTOMÁTICO DE AQUISIÇÃO</span><h2>Presentes grátis → relacionamento → oferta</h2><p>Configure anúncios que chegam no WhatsApp privado, entrega de presentes, entrada em grupo/página, aquecimento e venda. Marketing somente com consentimento.</p></div><div class="toolbar"><button class="secondary" data-action="funnel-template">Aplicar modelo inteligente</button><button data-action="funnel-agenda">Gerar agenda semanal</button></div></div>
  <div class="flow-grid section"><div class="flow-node"><b>1</b><span>📣 Anúncios</span><small>Meta Ads, Instagram ou tráfego</small></div><div class="flow-arrow">→</div><div class="flow-node"><b>2</b><span>💬 WhatsApp privado</span><small>Entrega e identificação do lead</small></div><div class="flow-arrow">→</div><div class="flow-node"><b>3</b><span>🎁 Grupo / Página</span><small>Materiais e relacionamento</small></div><div class="flow-arrow">→</div><div class="flow-node"><b>4</b><span>🔥 Aquecimento</span><small>Conteúdo programado</small></div><div class="flow-arrow">→</div><div class="flow-node"><b>5</b><span>💰 Oferta</span><small>Loja ou venda no privado</small></div></div>
  <div class="grid cards section"><div class="card metric"><small>Entraram no funil</small><strong>${d.stats?.entered||0}</strong></div><div class="card metric"><small>Autorizaram ofertas</small><strong>${d.stats?.optedIn||0}</strong></div><div class="card metric"><small>Geraram checkout</small><strong>${d.stats?.checkout||0}</strong></div><div class="card metric"><small>Viraram clientes</small><strong>${d.stats?.customers||0}</strong></div></div>
  <div class="alert warning section"><b>Uso responsável:</b> o funil automatiza o processo, mas não garante faturamento. Resultados dependem da oferta, tráfego, público, atendimento, reputação e conformidade. Ofertas privadas exigem autorização real do contato.</div>
  <form id="funnelForm" class="card form-grid section">
    <label class="check-line"><input type="checkbox" name="enabled" ${f.enabled?'checked':''}> Ativar funil de presentes</label><span></span>
    <label>Nome interno<input name="name" value="${esc(f.name)}"></label><label>Tag/origem do lead<input name="sourceTag" value="${esc(f.sourceTag)}"></label><label>Código da campanha<input name="campaignCode" value="${esc(f.campaignCode||'PRESENTE')}"></label><label>Mensagem pré-preenchida do anúncio<input name="adMessage" value="${esc(f.adMessage||'Olá! Quero receber o presente grátis.')}"></label><label class="full">Link pronto para o anúncio<div class="copy-row"><input id="adCampaignLink" readonly value="${esc(adLink)}" placeholder="Cadastre o número público em Configurações"><button type="button" data-copy="#adCampaignLink">Copiar</button></div></label>
    <label class="full">Palavras de entrada — uma por linha<textarea name="entryKeywords">${esc(lines(f.entryKeywords))}</textarea></label>
    <label>Link do grupo<input name="groupLink" value="${esc(f.groupLink)}" placeholder="https://chat.whatsapp.com/..."></label><label>Link da página de presentes<input name="pageLink" value="${esc(f.pageLink)}" placeholder="https://..."></label>
    <label class="full">Link da loja / ofertas<input name="storeLink" value="${esc(f.storeLink)}" placeholder="https://..."></label>
    <label class="full">Mensagem de boas-vindas<textarea name="welcomeMessage">${esc(f.welcomeMessage)}</textarea></label>
    <label class="full">Mensagem de consentimento<textarea name="consentMessage">${esc(f.consentMessage)}</textarea></label>
    <label class="full">Texto do link do grupo<textarea name="groupMessage">${esc(f.groupMessage)}</textarea></label>
    <label class="full">Texto da página de presentes<textarea name="pageMessage">${esc(f.pageMessage)}</textarea></label>
    <label class="full">Texto da loja<textarea name="storeMessage">${esc(f.storeMessage)}</textarea></label>
    <label class="check-line"><input type="checkbox" name="nurtureEnabled" ${f.privateNurture?.enabled?'checked':''}> Nutrição automática no privado</label><span></span>
    <label class="full">Sequência privada — minutos|tipo|mensagem<textarea name="sequence" class="json-editor" placeholder="30|transactional|Seu presente está aqui...\n1440|marketing|Posso mostrar uma oferta?">${esc(funnelSequenceLines(f.privateNurture?.sequence))}</textarea><small>Tipos: transactional ou marketing. Marketing só será enviado para contatos autorizados.</small></label>
    <label class="check-line"><input type="checkbox" name="warmupEnabled" ${f.groupWarmup?.enabled?'checked':''}> Aquecimento automático em grupos</label><span></span>
    <label>Presentes por dia<input name="giftsPerDay" type="number" min="0" max="20" value="${Number(f.groupWarmup?.giftsPerDay||0)}"></label><label>Ofertas por dia<input name="offersPerDay" type="number" min="0" max="10" value="${Number(f.groupWarmup?.offersPerDay||0)}"></label>
    <label>Horários dos presentes<input name="giftTimes" value="${esc((f.groupWarmup?.defaultGiftTimes||[]).join(','))}" placeholder="09:00,14:00,18:00"></label><label>Horários das ofertas<input name="offerTimes" value="${esc((f.groupWarmup?.defaultOfferTimes||[]).join(','))}" placeholder="20:00"></label>
    <label class="full">Grupos — Nome|ID@g.us|true<textarea name="groups" placeholder="Grupo Presentes 1|120363000000000000@g.us|true">${esc(groupsLines(d.groups))}</textarea></label>
    <div class="full toolbar"><button>Salvar funil</button><button type="button" class="secondary" data-action="funnel-template">Aplicar modelo</button><button type="button" class="secondary" data-action="funnel-agenda">Gerar agenda</button></div>
  </form>`;
}

async function renderCampaigns(){
  const [statusData,config]=await Promise.all([api('/api/campaigns'),api('/api/campaign-config')]); state.campaignConfig=config;
  const dModels=(config.disparos?.modelos||[]).filter(x=>x.ativo!==false); const mModels=(config.marketing?.modelos||[]).filter(x=>x.ativo!==false);
  $('#content').innerHTML=`<div class="hero-banner"><div><span class="eyebrow">CENTRAL DE CAMPANHAS</span><h2>Disparos, remarketing e conteúdo</h2><p>Inicie, pause e acompanhe campanhas pelo painel. O modo seguro exige consentimento para contatos privados.</p></div></div>
  <div class="grid cards section"><div class="card metric"><small>Disparos</small><strong>${esc(statusData.disparos.status||'idle')}</strong><span>${Number(statusData.disparos.enviados||0)} enviado(s)</span></div><div class="card metric"><small>Remarketing</small><strong>${esc(statusData.marketing.status||'idle')}</strong><span>${Number(statusData.marketing.enviados||0)} enviado(s)</span></div><div class="card metric"><small>Grupos</small><strong>${Array.isArray(config.groups)?config.groups.filter(x=>x.ativo!==false).length:0}</strong><span>ativo(s)</span></div><div class="card metric"><small>Agenda</small><strong>${config.agenda?.config?.ativo?'ativa':'desligada'}</strong><span>presentes e ofertas</span></div></div>
  <div class="grid two section">
    <div class="card"><h3>📨 Disparo controlado</h3><p class="muted">Envio para contatos autorizados, grupos ou ambos.</p><label>Modelo<select id="disparoModel">${dModels.map(x=>`<option value="${esc(x.id)}">${esc(x.titulo||x.id)}</option>`).join('')}</select></label><label>Destino<select id="disparoDestination"><option value="contatos">Contatos autorizados</option><option value="grupos">Grupos ativos</option><option value="todos">Contatos + grupos</option></select></label><div class="toolbar"><button data-action="campaign-start">Iniciar</button><button class="secondary" data-action="campaign-pause">Pausar</button><button class="secondary" data-action="campaign-resume">Continuar</button><button class="danger" data-action="campaign-cancel">Cancelar</button></div></div>
    <div class="card"><h3>🎯 Remarketing</h3><p class="muted">Somente para leads com autorização registrada.</p><label>Modelo<select id="remarketingModel">${mModels.map(x=>`<option value="${esc(x.id)}">${esc(x.titulo||x.id)}</option>`).join('')}</select></label><label>Segmento<select id="remarketingSegment"><option value="leads">Leads</option><option value="carrinho">Carrinho / PIX pendente</option><option value="clientes">Clientes</option><option value="todos">Todos autorizados</option></select></label><div class="toolbar"><button data-action="remarketing-start">Iniciar</button><button class="secondary" data-action="remarketing-pause">Pausar</button><button class="secondary" data-action="remarketing-resume">Continuar</button><button class="danger" data-action="remarketing-cancel">Cancelar</button></div></div>
  </div>
  <div class="alert warning section"><b>Proteção:</b> não use listas sem autorização. Intervalos não transformam spam em envio seguro. Revise textos, público e opt-in antes de iniciar.</div>
  <div class="tabs" id="campaignTabs"><button class="active" data-campaign-tab="groups">Grupos</button><button data-campaign-tab="agenda">Agenda</button><button data-campaign-tab="disparos">Disparos</button><button data-campaign-tab="marketing">Remarketing</button></div><div class="card"><form id="campaignForm"><input type="hidden" name="type" value="groups"><label>Editor avançado da configuração<textarea class="json-editor" name="json">${esc(JSON.stringify(config.groups,null,2))}</textarea></label><div class="toolbar"><button>Salvar configuração</button><button type="button" class="secondary" data-action="format-json">Formatar JSON</button><button type="button" class="secondary" data-go="funnel">Editor visual do funil e grupos</button></div></form></div>`;
}


async function renderIntegrations(){ const d=await api('/api/integrations'); state.integrations=d; const c=d.config; const evo=c.whatsapp.evolution; $('#content').innerHTML=`<div class="hero-banner"><div><h2>Integrações sem editar código</h2><p>Escolha o WhatsApp, conecte Evolution API, importe leads, baixe a extensão e envie eventos para n8n, Make ou CRM.</p></div></div>
  <div class="card section"><div class="integration-card"><div class="integration-icon">💬</div><div><h3>Provedor do WhatsApp</h3><p class="muted">QR direto usa WhatsApp Web. Evolution API usa sua instância externa e webhooks.</p></div>${status(c.whatsapp.provider)}</div><form id="integrationForm" class="form-grid"><label>URL pública do painel<input name="publicBaseUrl" value="${esc(c.publicBaseUrl||d.publicBaseUrl)}" placeholder="https://seu-subdominio.squareweb.app"></label><label>Modo de conexão<select name="provider"><option value="local" ${c.whatsapp.provider==='local'?'selected':''}>QR Code direto</option><option value="evolution" ${c.whatsapp.provider==='evolution'?'selected':''}>Evolution API v2</option></select></label><span></span><label>URL da Evolution API<input name="baseUrl" value="${esc(evo.baseUrl)}" placeholder="https://evolution.seudominio.com"></label><label>Nome da instância<input name="instance" value="${esc(evo.instance)}"></label><label class="full">API Key<input name="evolutionApiKey" type="password" placeholder="${esc(c.secrets.evolutionApiKey||'Cole a API Key')}"></label>
  <div class="full toolbar"><button>Salvar integração</button><button type="button" class="secondary" data-action="evo-test">Testar conexão</button><button type="button" class="secondary" data-action="evo-create">Criar instância</button><button type="button" class="secondary" data-action="evo-qr">Ver QR</button><button type="button" class="secondary" data-action="evo-webhook">Configurar webhook</button><button type="button" class="warning" data-action="restart-app">Reiniciar aplicação</button></div></form><div class="note" style="margin-top:14px">Ao trocar o provedor, reinicie a aplicação. Webhook Evolution: <span class="code">${esc(d.publicBaseUrl)}/webhooks/evolution/${esc(evo.instance||'INSTANCIA')}/TOKEN_SEGURO</span></div></div>
  <div class="grid two section"><div class="card"><div class="integration-card"><div class="integration-icon">🧲</div><div><h3>Extrator e importação de leads</h3><p class="muted">API segura, CSV e extensão Chrome.</p></div><span class="status active">ativo</span></div><div class="copy-row"><input id="leadEndpoint" readonly value="${esc(d.leadEndpoint)}"><button type="button" data-copy="#leadEndpoint">Copiar</button></div><label style="margin-top:12px">Token do extrator<div class="copy-row"><input id="leadToken" readonly value="${esc(c.secrets.leadImportToken)}"><button type="button" data-copy="#leadToken">Copiar</button></div></label><div class="toolbar" style="margin-top:14px"><a href="${esc(d.extensionUrl)}" class="button-link" download><button type="button">Baixar extensão JETBOT Leads</button></a><button type="button" class="secondary" data-action="import-leads">Importar CSV/JSON</button></div><div class="note" style="margin-top:14px">Leads importados entram sem consentimento de marketing, a menos que a origem informe autorização real.</div></div>
  <div class="card"><div class="integration-card"><div class="integration-icon">🔗</div><div><h3>Webhook para n8n, Make ou CRM</h3><p class="muted">Envia eventos de leads, vendas e suporte.</p></div></div><form id="outboundForm"><label class="check-line"><input type="checkbox" name="enabled" ${c.outboundWebhook.enabled?'checked':''}> Ativar webhook de saída</label><label>URL de destino<input name="url" value="${esc(c.outboundWebhook.url)}" placeholder="https://..."></label><label>Eventos, separados por vírgula<input name="events" value="${esc((c.outboundWebhook.events||[]).join(','))}"></label><label>Segredo para assinatura<input name="outboundWebhookSecret" type="password" placeholder="${esc(c.secrets.outboundWebhookSecret||'Opcional')}"></label><div class="toolbar"><button>Salvar webhook</button><button type="button" class="secondary" data-action="outbound-test">Enviar evento de teste</button></div></form></div></div>
  <div class="card section"><h3>Enviar mensagem de teste</h3><form id="testMessageForm" class="form-grid"><label>Número com DDI<input name="number" placeholder="5551999999999" required></label><label>Mensagem<input name="text" value="✅ Teste do robô vendedor realizado com sucesso."></label><div class="full"><button>Enviar teste</button></div></form></div>`; }

async function renderSettings(){ const [c,a]=await Promise.all([api('/api/settings'),api('/api/ai')]); state.settings=c; $('#brandName').textContent=c.bot.nome||'JETBOT'; $('#content').innerHTML=`<div class="tabs"><button class="active" data-settings-tab="business">Negócio</button><button data-settings-tab="sales">Vendas</button><button data-settings-tab="payments">Pagamentos</button><button data-settings-tab="ai">Inteligência artificial</button></div><div id="settingsPanel">${businessSettings(c)}</div>`; state.ai=a; }
function businessSettings(c){ return `<div class="card"><h3>Identidade e atendimento</h3><form id="businessSettings" class="form-grid"><label>Nome da marca<input name="nome" value="${esc(c.bot.nome)}"></label><label>Nome do assistente<input name="nomeAssistente" value="${esc(c.bot.nomeAssistente)}"></label><label>Tipo de negócio<select name="tipoNegocio">${businessOptions(c.bot.tipoNegocio)}</select></label><label>Tom de voz<input name="tomDeVoz" value="${esc(c.bot.tomDeVoz)}"></label><label class="full">Descrição do negócio<textarea name="descricaoNegocio">${esc(c.bot.descricaoNegocio)}</textarea></label><label>Link principal<input name="linkPrincipal" value="${esc(c.bot.linkPrincipal)}"></label><label>Número público do WhatsApp<input name="whatsappPublicNumber" value="${esc(c.bot.whatsappPublicNumber||'')}" placeholder="5551999999999"></label><label>Logo da marca (URL)<input name="logoUrl" value="${esc(c.bot.logoUrl||'')}" placeholder="https://..."></label><label>Cor principal<input name="primaryColor" type="color" value="${esc(c.bot.primaryColor||'#00e676')}"></label><label class="full">Título da loja pública<input name="catalogTitle" value="${esc(c.bot.catalogTitle||'Conheça nossas soluções')}"></label><label class="full">Subtítulo da loja pública<textarea name="catalogSubtitle">${esc(c.bot.catalogSubtitle||'')}</textarea></label><label>Link de presentes<input name="linkPresentes" value="${esc(c.bot.linkPresentes)}"></label><label>E-mail de suporte<input name="emailSuporte" value="${esc(c.bot.emailSuporte)}"></label><label>Horário de atendimento<input name="horarioAtendimento" value="${esc(c.bot.horarioAtendimento)}"></label><label class="full">Saudação<textarea name="saudacao">${esc(c.bot.saudacao)}</textarea></label><label class="full">Mensagem de suporte<textarea name="mensagemSuporte">${esc(c.bot.mensagemSuporte)}</textarea></label><label class="full">Termos de compra<textarea name="termosDeCompra">${esc(c.bot.termosDeCompra)}</textarea></label><label class="full">Administradores — um por linha<textarea name="adminNumbers">${esc(lines(c.bot.adminNumbers))}</textarea></label><label class="check-line"><input type="checkbox" name="ignorarGrupos" ${c.bot.ignorarGrupos?'checked':''}> Ignorar mensagens comuns em grupos</label><div class="full toolbar"><button>Salvar negócio</button><button type="button" class="secondary" data-action="apply-template-settings">Aplicar modelo do segmento</button></div></form></div>`; }
function salesSettings(c){ return `<div class="card"><h3>Fluxo de venda</h3><form id="salesSettings" class="form-grid"><label class="check-line"><input type="checkbox" name="explicarAntesDoPagamento" ${c.vendas.explicarAntesDoPagamento?'checked':''}> Explicar produto antes do pagamento</label><label class="check-line"><input type="checkbox" name="pedirConfirmacaoCompra" ${c.vendas.pedirConfirmacaoCompra?'checked':''}> Pedir confirmação para comprar</label><label class="check-line"><input type="checkbox" name="mostrarEstoque" ${c.vendas.mostrarEstoque?'checked':''}> Mostrar quantidade em estoque</label><label class="check-line"><input type="checkbox" name="mostrarGarantia" ${c.vendas.mostrarGarantia?'checked':''}> Mostrar garantia</label><label class="check-line"><input type="checkbox" name="catalogoPublicoAtivo" ${c.vendas.catalogoPublicoAtivo!==false?'checked':''}> Ativar loja pública no subdomínio</label><label>Símbolo da moeda<input name="simboloMoeda" value="${esc(c.vendas.simboloMoeda)}"></label><span></span><label class="full">Mensagem sem estoque<textarea name="mensagemSemEstoque">${esc(c.vendas.mensagemSemEstoque)}</textarea></label><label class="full">Mensagem sem pagamento<textarea name="mensagemSemPagamento">${esc(c.vendas.mensagemSemPagamento)}</textarea></label><div class="full"><button>Salvar vendas</button></div></form></div>`; }
function paymentSettings(c){ return `<div class="card"><h3>Formas de pagamento</h3><form id="paymentSettings" class="form-grid"><label class="check-line"><input type="checkbox" name="mpAtivo" ${c.pagamentos.mercadoPago.ativo?'checked':''}> Mercado Pago ativo</label><label>Access Token Mercado Pago<input type="password" name="mercadoPagoToken" placeholder="${esc(c.pagamentos.mercadoPago.accessToken||'Cole o token')}"></label><label class="check-line"><input type="checkbox" name="pushAtivo" ${c.pagamentos.pushinpay.ativo?'checked':''}> PushinPay ativa</label><label>Token PushinPay<input type="password" name="pushinpayToken" placeholder="${esc(c.pagamentos.pushinpay.apiToken||'Cole o token')}"></label><label class="check-line"><input type="checkbox" name="pixAtivo" ${c.pagamentos.pixManual.ativo?'checked':''}> PIX manual ativo</label><label>Chave PIX<input name="pixKey" placeholder="${esc(c.pagamentos.pixManual.chavePix||'Sua chave')}"></label><div class="full"><button>Salvar pagamentos</button></div></form></div>`; }
function aiSettings(a){ return `<div class="card"><h3>Atendimento inteligente</h3><form id="aiSettings" class="form-grid"><label class="check-line"><input type="checkbox" name="iaAtiva" ${a.iaAtiva?'checked':''}> IA ativada</label><label>Token Groq<input type="password" name="token" placeholder="${esc(a.groqToken||'Cole o token')}"></label><label>Modelo<input name="model" value="${esc(a.model)}"></label><label>Memória de mensagens<input name="maxHistoryMessages" type="number" min="4" max="30" value="${a.maxHistoryMessages}"></label><label>Temperatura<input name="temperature" type="number" step="0.1" min="0" max="1.5" value="${a.temperature}"></label><span></span><label class="full">Prompt principal<textarea class="json-editor" name="promptSistema">${esc(a.promptSistema)}</textarea></label><div class="full"><button>Salvar IA</button></div></form><div class="note" style="margin-top:14px">A IA recebe automaticamente o catálogo, benefícios, FAQ, preço e disponibilidade. Ela não pode aprovar pagamentos nem inventar informações.</div></div>`; }

async function renderSecurity(){ const [backups,audit,diag]=await Promise.all([api('/api/backups'),api('/api/audit?limit=100'),api('/api/diagnostics')]); $('#content').innerHTML=`<div class="hero-banner"><div><h2>Segurança e diagnóstico</h2><p>Backups, auditoria e checagem completa da operação.</p></div><div class="toolbar"><button data-action="create-backup">Criar backup</button><a class="button-link" href="/catalogo" target="_blank"><button type="button" class="secondary">Abrir loja pública</button></a><button class="secondary" data-action="diagnostics">Executar diagnóstico</button></div></div><div class="card section"><h3>Diagnóstico atual</h3><div class="check-grid">${diag.checks.map(c=>`<div class="diagnostic"><span>${esc(c.label)}</span><b class="${c.ok?'ok':'no'}">${c.ok?'✓ OK':'✕ Pendente'}</b></div>`).join('')}</div></div><div class="grid two section"><div class="card"><h3>Backups</h3>${backups.map(b=>`<div class="diagnostic"><span>${esc(b.filename)}<br><small class="muted">${fmtDate(b.createdAt||b.mtime)}</small></span><div class="toolbar"><a href="/api/backups/${encodeURIComponent(b.filename)}/download"><button class="small-btn secondary">Baixar</button></a><button class="small-btn warning" data-action="restore-backup" data-id="${esc(b.filename)}">Restaurar</button></div></div>`).join('')||empty('Nenhum backup.')}</div><div class="card"><h3>Auditoria recente</h3>${audit.slice(0,30).map(x=>`<div class="diagnostic"><span><b>${esc(x.action)}</b><br><small class="muted">${fmtDate(x.timestamp)} · ${esc(x.actor||'system')}</small></span></div>`).join('')||empty('Sem registros.')}</div></div>`; }

function openCategoryModal(){ openModal(`<h2>Nova categoria</h2><form id="categoryForm"><label>Nome<input name="nome" required placeholder="Ex.: Planos, Cursos, Serviços"></label><div class="toolbar"><button>Salvar</button><button type="button" class="secondary" data-close>Cancelar</button></div></form>`); }
async function openProductModal(id){ await loadProducts(); const p=state.products.find(x=>x.id===id)||{}; openModal(productForm(p),true); }
async function openStockModal(id){ const p=state.products.find(x=>x.id===id); const d=await api(`/api/products/${id}/stock`); openModal(`<h2>Estoque — ${esc(p?.nome)}</h2><div class="note">Uma linha representa uma entrega completa. Não quebre usuário, senha e link em linhas diferentes.</div><form id="stockForm"><input type="hidden" name="id" value="${id}"><label>Modo<select name="mode"><option value="replace">Substituir estoque atual</option><option value="append">Adicionar ao estoque</option></select></label><label>Itens<textarea class="json-editor" name="items">${esc(d.items.join('\n'))}</textarea></label><button>Salvar estoque</button></form>`,true); }
function openLeadImport(){ openModal(`<h2>Importar leads</h2><p class="muted">CSV: telefone;nome;empresa;email;consent. Também aceita JSON.</p><form id="leadImportForm"><label>Formato<select name="format"><option value="csv">CSV</option><option value="json">JSON</option></select></label><label>Origem<input name="source" value="Importação pelo painel"></label><label>Conteúdo<textarea class="json-editor" name="content" placeholder="telefone;nome;empresa;email\n5551999999999;João;Empresa;email@exemplo.com"></textarea></label><label class="check-line"><input type="checkbox" name="defaultConsent"> Os contatos comprovaram autorização para ofertas</label><button>Importar</button></form>`,true); }
function openLeadEdit(id,lead){ openModal(`<h2>Editar lead</h2><form id="leadEditForm" class="form-grid"><input type="hidden" name="id" value="${esc(id)}"><label>Nome<input name="nome" value="${esc(lead.nome)}"></label><label>Empresa<input name="empresa" value="${esc(lead.empresa)}"></label><label>Etapa<select name="stage">${['new','interested','checkout','customer','lost'].map(x=>`<option ${x===lead.stage?'selected':''}>${x}</option>`).join('')}</select></label><label class="check-line"><input type="checkbox" name="optIn" ${lead.optIn?'checked':''}> Autorizou ofertas</label><label class="full">Observações<textarea name="notes">${esc(lead.notes)}</textarea></label><div class="full"><button>Salvar</button></div></form>`); }

