document.addEventListener('click',async e=>{
  const go=e.target.closest('[data-go]'); if(go){navigate(go.dataset.go);return}
  if(e.target.closest('[data-close]')){closeModal();return}
  const copy=e.target.closest('[data-copy]'); if(copy){copyText($(copy.dataset.copy).value);return}
  const a=e.target.closest('[data-action]'); if(!a)return; const action=a.dataset.action,id=a.dataset.id;
  try{
    if(action==='new-category')openCategoryModal();
    if(action==='new-product')openProductModal();
    if(action==='edit-product')openProductModal(id);
    if(action==='stock')openStockModal(id);
    if(action==='delete-product'){if(confirm('Excluir produto e estoque?')){await api(`/api/products/${id}`,{method:'DELETE'});toast('Produto excluído.');renderProducts()}}
    if(action==='deliver-order'){if(confirm('Confirmar/realizar a entrega deste pedido?')){await api(`/api/orders/${id}/deliver`,{method:'POST'});toast('Processamento executado.');renderOrders()}}
    if(action==='import-leads')openLeadImport();
    if(action==='edit-lead'){const leads=await api('/api/leads');const lead=leads.find(l=>(l.chatId||l.id)===decodeURIComponent(id));openLeadEdit(decodeURIComponent(id),lead||{})}
    if(action==='resolve-ticket'){await api(`/api/tickets/${id}`,{method:'PUT',body:{status:'resolved'}});toast('Chamado resolvido.');renderTickets()}
    if(action==='run-automation'){const r=await api('/api/automation/run',{method:'POST'});toast(`Processadas: ${r.processed||0}`);renderAutomation()}
    if(action==='run-monitor'||action==='diagnostics'){const r=action==='diagnostics'?await api('/api/diagnostics'):await api('/api/automation/monitor',{method:'POST'});openModal(`<h2>Diagnóstico</h2><div class="setup-list">${(r.checks||[]).map(c=>setupRow(c.label,c.ok)).join('')||`<pre class="code">${esc(JSON.stringify(r,null,2))}</pre>`}</div>`,true)}
    if(action==='retry-job'){await api(`/api/automation/jobs/${id}/retry`,{method:'POST'});toast('Tarefa reagendada.');renderAutomation()}
    if(action==='cancel-job'){await api(`/api/automation/jobs/${id}/cancel`,{method:'POST'});toast('Tarefa cancelada.');renderAutomation()}
    if(action==='resolve-alert'){await api(`/api/automation/alerts/${id}/resolve`,{method:'POST'});renderAutomation()}
    if(action==='create-backup'){await api('/api/backups',{method:'POST'});toast('Backup criado.');renderSecurity()}
    if(action==='restore-backup'){if(confirm('Restaurar este backup? Os dados atuais serão substituídos.')){await api(`/api/backups/${encodeURIComponent(id)}/restore`,{method:'POST'});toast('Backup restaurado. Reinicie a aplicação.')}}
    if(action==='show-qr'){const s=await api('/api/status');openModal(`<h2>Conectar WhatsApp</h2>${s.whatsapp.qrDataUrl?`<img class="qr" src="${s.whatsapp.qrDataUrl}">`:empty('QR ainda não disponível.')}`)}
    if(action==='apply-template'){const f=$('#setupBusiness');const fd=formDataObject(f);await api('/api/setup/template',{method:'POST',body:{type:fd.tipoNegocio,brand:fd.nome}});toast('Modelo aplicado.');renderSetup()}
    if(action==='setup-product-template'){const c=await api('/api/settings');const r=await api('/api/setup/first-product',{method:'POST',body:{type:c.bot.tipoNegocio}});toast(`Modelo ${r.nome} criado. Edite antes de ativar vendas.`);renderSetup()}
    if(action==='complete-setup'){await api('/api/setup/complete',{method:'POST'});toast('Setup concluído!');navigate('dashboard')}
    if(action==='apply-template-settings'){const c=state.settings;await api('/api/settings/template',{method:'POST',body:{type:c.bot.tipoNegocio,brand:c.bot.nome}});toast('Modelo aplicado.');renderSettings()}
    if(action==='format-json'){const ta=$('#campaignForm textarea');ta.value=JSON.stringify(JSON.parse(ta.value),null,2);toast('JSON formatado.')}
    if(action==='campaign-start'){await api('/api/campaigns/disparos/start',{method:'POST',body:{modelId:$('#disparoModel')?.value,destination:$('#disparoDestination')?.value}});toast('Campanha iniciada.');renderCampaigns()}
    if(action==='campaign-pause'){await api('/api/campaigns/disparos/pause',{method:'POST'});toast('Campanha pausada.');renderCampaigns()}
    if(action==='campaign-resume'){await api('/api/campaigns/disparos/resume',{method:'POST'});toast('Campanha retomada.');renderCampaigns()}
    if(action==='campaign-cancel'){if(confirm('Cancelar a campanha de disparos?')){await api('/api/campaigns/disparos/cancel',{method:'POST'});toast('Campanha cancelada.');renderCampaigns()}}
    if(action==='remarketing-start'){await api('/api/campaigns/remarketing/start',{method:'POST',body:{modelId:$('#remarketingModel')?.value,segment:$('#remarketingSegment')?.value}});toast('Remarketing iniciado.');renderCampaigns()}
    if(action==='remarketing-pause'){await api('/api/campaigns/remarketing/pause',{method:'POST'});toast('Remarketing pausado.');renderCampaigns()}
    if(action==='remarketing-resume'){await api('/api/campaigns/remarketing/resume',{method:'POST'});toast('Remarketing retomado.');renderCampaigns()}
    if(action==='remarketing-cancel'){if(confirm('Cancelar o remarketing?')){await api('/api/campaigns/remarketing/cancel',{method:'POST'});toast('Remarketing cancelado.');renderCampaigns()}}
    if(action==='evo-test'){const r=await api('/api/integrations/evolution/test',{method:'POST'});openModal(`<h2>Evolution API</h2><pre class="code">${esc(JSON.stringify(r.data,null,2))}</pre>`)}
    if(action==='evo-create'){if(confirm('Criar a instância configurada na Evolution API?')){const r=await api('/api/integrations/evolution/create',{method:'POST',body:{publicBaseUrl:state.integrations.publicBaseUrl}});openModal(`<h2>Instância criada</h2><pre class="code">${esc(JSON.stringify(r.data,null,2))}</pre>`,true)}}
    if(action==='evo-qr'){const r=await api('/api/integrations/evolution/qr');openModal(`<h2>QR Code Evolution</h2>${r.qrDataUrl?`<img class="qr" src="${esc(r.qrDataUrl)}">`:empty('QR não retornado. A instância pode já estar conectada.')}<pre class="code">${esc(JSON.stringify({pairingCode:r.pairingCode,count:r.count},null,2))}</pre>`)}
    if(action==='evo-webhook'){const r=await api('/api/integrations/evolution/configure-webhook',{method:'POST',body:{publicBaseUrl:state.integrations.publicBaseUrl}});openModal(`<h2>Webhook configurado</h2><div class="code">${esc(r.webhookUrl)}</div>`)}
    if(action==='funnel-template'){const c=await api('/api/settings');await api('/api/funnel/template',{method:'POST',body:{brand:c.bot.nome}});toast('Modelo do funil aplicado.');renderFunnel()}
    if(action==='funnel-agenda'){if(confirm('Gerar e substituir a agenda semanal com base neste funil?')){await api('/api/funnel/generate-agenda',{method:'POST'});toast('Agenda semanal gerada.');renderFunnel()}}
    if(action==='outbound-test'){const r=await api('/api/integrations/outbound/test',{method:'POST'});openModal(`<h2>Webhook de saída</h2><pre class="code">${esc(JSON.stringify(r,null,2))}</pre>`)}
    if(action==='restart-app'){if(confirm('Reiniciar a aplicação agora? Ela ficará indisponível por alguns segundos.')){await api('/api/system/restart',{method:'POST'});toast('Reiniciando...','success')}}
  }catch(err){toast(err.message,'error')}
});

document.addEventListener('submit',async e=>{
  const f=e.target;if(!f.matches('form'))return;e.preventDefault();const fd=formDataObject(f);
  try{
    if(f.id==='setupBusiness'||f.id==='businessSettings'){
      const c=await api('/api/settings'); c.bot={...c.bot,...fd,adminNumbers:f.adminNumbers?parseLines(f.adminNumbers.value):c.bot.adminNumbers,ignorarGrupos:f.ignorarGrupos?f.ignorarGrupos.checked:c.bot.ignorarGrupos}; await api('/api/settings',{method:'PUT',body:{config:c}});toast('Configurações salvas.');f.id==='setupBusiness'?renderSetup():renderSettings();
    }
    if(f.id==='setupAdmins'){const c=await api('/api/settings');c.bot.adminNumbers=parseLines(fd.adminNumbers);await api('/api/settings',{method:'PUT',body:{config:c}});toast('Administradores salvos.');renderSetup()}
    if(f.id==='categoryForm'){await api('/api/categories',{method:'POST',body:{nome:fd.nome}});closeModal();toast('Categoria criada.');renderProducts()}
    if(f.id==='productForm'){
      const body={...fd,preco:Number(fd.preco),precoDe:Number(fd.precoDe||0),validityDays:Number(fd.validityDays||0),lowStockThreshold:Number(fd.lowStockThreshold||0),ordem:Number(fd.ordem||0),beneficios:parseLines(fd.beneficios),inclui:parseLines(fd.inclui),faq:parseFaq(fd.faq),ativo:f.ativo.checked,destaque:f.destaque.checked,entregaAutomatica:f.entregaAutomatica.checked};delete body.id;
      if(body.categoriaId==='__new__'){const cat=await api('/api/categories',{method:'POST',body:{nome:'Produtos'}});body.categoriaId=cat.id;}
      if(fd.id)await api(`/api/products/${fd.id}`,{method:'PUT',body});else await api('/api/products',{method:'POST',body}); closeModal();toast('Produto salvo.');state.page==='setup'?renderSetup():renderProducts();
    }
    if(f.id==='stockForm'){await api(`/api/products/${fd.id}/stock`,{method:'POST',body:{mode:fd.mode,items:parseLines(fd.items)}});closeModal();toast('Estoque atualizado.');renderProducts()}
    if(f.classList.contains('ticketReply')){await api(`/api/tickets/${f.dataset.id}/reply`,{method:'POST',body:{text:fd.text,resolve:fd.resolve==='1'}});toast('Resposta enviada.');renderTickets()}
    if(f.id==='leadImportForm'){let items;if(fd.format==='json')items=JSON.parse(fd.content);else items=parseCsvClient(fd.content);const r=await api('/api/leads/import',{method:'POST',body:{items,options:{source:fd.source,defaultConsent:f.defaultConsent.checked,consentSource:'Importação pelo painel'}}});closeModal();toast(`${r.created} criado(s), ${r.updated} atualizado(s).`);renderCrm()}
    if(f.id==='leadEditForm'){await api(`/api/leads/${encodeURIComponent(fd.id)}`,{method:'PUT',body:{nome:fd.nome,empresa:fd.empresa,stage:fd.stage,optIn:f.optIn.checked,optOut:!f.optIn.checked,notes:fd.notes}});closeModal();toast('Lead atualizado.');renderCrm()}
    if(f.id==='automationForm'){let cfg=JSON.parse(fd.advanced);cfg.enabled=f.enabled.checked;cfg.workerIntervalSeconds=Number(fd.workerIntervalSeconds);cfg.limits.maxMessagesPerContactPerDay=Number(fd.maxMessages);cfg.limits.maxMarketingPerContactPerDay=Number(fd.maxMarketing);cfg.quietHours.start=fd.quietStart;cfg.quietHours.end=fd.quietEnd;await api('/api/automation/config',{method:'PUT',body:cfg});toast('Automação salva. Reinicie se mudou intervalos.');renderAutomation()}
    if(f.id==='campaignForm'){await api(`/api/campaign-config/${fd.type}`,{method:'PUT',body:JSON.parse(fd.json)});toast('Configuração salva.')}
    if(f.id==='funnelForm'){const current=(await api('/api/funnel')).config;const body={...current,enabled:f.enabled.checked,name:fd.name,sourceTag:fd.sourceTag,campaignCode:fd.campaignCode,adMessage:fd.adMessage,entryKeywords:parseLines(fd.entryKeywords),groupLink:fd.groupLink,pageLink:fd.pageLink,storeLink:fd.storeLink,welcomeMessage:fd.welcomeMessage,consentMessage:fd.consentMessage,groupMessage:fd.groupMessage,pageMessage:fd.pageMessage,storeMessage:fd.storeMessage,privateNurture:{...current.privateNurture,enabled:f.nurtureEnabled.checked,sequence:parseFunnelSequence(fd.sequence)},groupWarmup:{...current.groupWarmup,enabled:f.warmupEnabled.checked,giftsPerDay:Number(fd.giftsPerDay||0),offersPerDay:Number(fd.offersPerDay||0),defaultGiftTimes:String(fd.giftTimes||'').split(',').map(x=>x.trim()).filter(Boolean),defaultOfferTimes:String(fd.offerTimes||'').split(',').map(x=>x.trim()).filter(Boolean)}};await api('/api/funnel',{method:'PUT',body:{config:body,groups:parseGroups(fd.groups)}});toast('Funil salvo.');renderFunnel()}
    if(f.id==='integrationForm'){const current=(await api('/api/integrations')).config;current.publicBaseUrl=fd.publicBaseUrl;current.whatsapp.provider=fd.provider;current.whatsapp.evolution={...current.whatsapp.evolution,baseUrl:fd.baseUrl,instance:fd.instance,enabled:fd.provider==='evolution'};await api('/api/integrations',{method:'PUT',body:{config:current,secrets:{evolutionApiKey:fd.evolutionApiKey}}});toast('Integração salva. Reinicie a aplicação.');renderIntegrations()}
    if(f.id==='outboundForm'){const current=(await api('/api/integrations')).config;current.outboundWebhook={...current.outboundWebhook,enabled:f.enabled.checked,url:fd.url,events:fd.events.split(',').map(x=>x.trim()).filter(Boolean)};await api('/api/integrations',{method:'PUT',body:{config:current,secrets:{outboundWebhookSecret:fd.outboundWebhookSecret}}});toast('Webhook salvo.');renderIntegrations()}
    if(f.id==='testMessageForm'){await api('/api/integrations/test-message',{method:'POST',body:fd});toast('Mensagem enviada.')}
    if(f.id==='salesSettings'){const c=await api('/api/settings');c.vendas={...c.vendas,...fd,explicarAntesDoPagamento:f.explicarAntesDoPagamento.checked,pedirConfirmacaoCompra:f.pedirConfirmacaoCompra.checked,mostrarEstoque:f.mostrarEstoque.checked,mostrarGarantia:f.mostrarGarantia.checked,catalogoPublicoAtivo:f.catalogoPublicoAtivo.checked};await api('/api/settings',{method:'PUT',body:{config:c}});toast('Vendas atualizadas.');renderSettings()}
    if(f.id==='paymentSettings'){const c=await api('/api/settings');c.pagamentos.mercadoPago.ativo=f.mpAtivo.checked;c.pagamentos.pushinpay.ativo=f.pushAtivo.checked;c.pagamentos.pixManual.ativo=f.pixAtivo.checked;await api('/api/settings',{method:'PUT',body:{config:c,secrets:{mercadoPagoToken:fd.mercadoPagoToken,pushinpayToken:fd.pushinpayToken,pixKey:fd.pixKey}}});toast('Pagamentos atualizados.');renderSettings()}
    if(f.id==='aiSettings'){await api('/api/ai',{method:'PUT',body:{config:{iaAtiva:f.iaAtiva.checked,model:fd.model,maxHistoryMessages:Number(fd.maxHistoryMessages),temperature:Number(fd.temperature),promptSistema:fd.promptSistema},token:fd.token}});toast('IA atualizada.');renderSettings()}
  }catch(err){toast(err.message,'error')}
});

function parseCsvClient(text){const lines=String(text).replace(/^\uFEFF/,'').split(/\r?\n/).filter(x=>x.trim());if(!lines.length)return[];const sep=lines[0].includes(';')?';':',';const h=lines[0].split(sep).map(x=>x.trim().toLowerCase());return lines.slice(1).map(line=>{const vals=line.split(sep).map(x=>x.trim());const o={};h.forEach((k,i)=>o[k]=vals[i]||'');return o})}

document.addEventListener('click',e=>{
  const tab=e.target.closest('[data-settings-tab]');if(tab){$$('[data-settings-tab]').forEach(x=>x.classList.toggle('active',x===tab));const c=state.settings;$('#settingsPanel').innerHTML=tab.dataset.settingsTab==='business'?businessSettings(c):tab.dataset.settingsTab==='sales'?salesSettings(c):tab.dataset.settingsTab==='payments'?paymentSettings(c):aiSettings(state.ai)}
  const ctab=e.target.closest('[data-campaign-tab]');if(ctab){$$('[data-campaign-tab]').forEach(x=>x.classList.toggle('active',x===ctab));const type=ctab.dataset.campaignTab;const f=$('#campaignForm');f.elements.type.value=type;f.elements.json.value=JSON.stringify(state.campaignConfig[type],null,2)}
});

(async()=>{const me=await fetch('/api/auth/me').then(r=>r.json()).catch(()=>({}));if(me.authenticated){showApp();await refreshStatus();const s=await api('/api/setup');navigate(s.completed?'dashboard':'setup');setInterval(refreshStatus,10000)}else showLogin()})();
